import http from '../http'




// 分页查询原始模板
export function testOriginalRecordTemplateList(query: any) {
    return http.get('/jkyErp/testOriginalRecordTemplate/list', query)
}

// 查询单个模板
export function gettestOriginalRecordTemplate(id: any) {
    return http.get('/jkyErp/testOriginalRecordTemplate/' + id)
}
// 新增原始模板
export function addtestOriginalRecordTemplate(data: any) {
    return http.post('/jkyErp/testOriginalRecordTemplate/add', data)
}

// 修改原始模板
export function editestOriginalRecordTemplate(data: any) {
    return http.post('/jkyErp/testOriginalRecordTemplate/edit', data)
}

// 删除原始模板
export function deltestOriginalRecordTemplate(teamId: number) {
    return http.post('/jkyErp/testOriginalRecordTemplate/del',teamId)
}







