<template>
  <a-card>
    <div :class="advanced ? 'search' : null">
      <a-form layout="horizontal">
        <div :class="advanced ? null : 'fold'">
          <a-row>
            <a-col :md="8" :sm="24">
              <a-form-item
                label="模板名称"
                :labelCol="{ span: 5 }"
                :wrapperCol="{ span: 18, offset: 1 }"
              >
                <a-input
                  placeholder="请输入模板名称"
                  v-model:value="queryParams.name"
                />
              </a-form-item>
            </a-col>
          </a-row>
        </div>
        <span style="float: right; margin-top: 3px">
          <a-button type="primary" @click="handleSearch">查询</a-button>
          <a-button style="margin-left: 8px" @click="Reset">重置</a-button>
          <a @click="toggleAdvanced" style="margin-left: 8px">
            {{ advanced ? "收起" : "展开" }}
          </a>
        </span>
      </a-form>
    </div>
    <div>
      <a-space class="operator">
        <a-button @click="handleAdd" type="primary">新建</a-button>
        <a-button
          @click="handleUpdate"
          type="primary"
          :disabled="selectedRowKeys.length == 1 ? false : true"
          >编辑</a-button
        >
        <a-button
          @click="handleDel"
          type="primary"
          :disabled="selectedRowKeys.length > 0 ? false : true"
          danger
          >删除
        </a-button>
      </a-space>
      <a-table
        rowKey="id"
        :pagination="false"
        :columns="columns"
        :data-source="dataSource"
        :row-selection="{
          selectedRowKeys: selectedRowKeys,
          onChange: onSelectChange,
        }"
      >
        <template #isAvailable="{ text }">
          {{ text == "1" ? "是" : "否" }}
        </template>
        <template #operation="{ record }">
          <a @click="onSel(record.fileUrl)" v-if="record.fileUrl">下载</a>
        </template>
      </a-table>
      <a-pagination
        v-show="total > 0"
        show-size-changer
        :show-total="(total) => `共 ${total} 条`"
        v-model:current="queryParams.current"
        v-model:pageSize="queryParams.size"
        :total="total"
        show-less-items
        @showSizeChange="onShowSizeChange"
        @change="onPageChange"
      />
    </div>
  </a-card>

  <a-modal
    :visible="open"
    :title="title"
    width="650px"
    @ok="handleOk"
    @cancel="handleCancel"
  >
    <a-form :model="form" :rules="rules">
      <a-row :gutter="[16, 16]">
        <a-col :span="12">
          <a-form-item label="模板编号">
            <a-input placeholder="请输入模板编号" v-model:value="form.code" />
          </a-form-item>
        </a-col>
        <a-col :span="12">
          <a-form-item label="是否可用">
            <a-radio-group v-model:value="form.isAvailable">
              <a-radio value="1">是</a-radio>
              <a-radio value="2">否</a-radio>
            </a-radio-group>
          </a-form-item>
        </a-col>
      </a-row>

      <a-row :gutter="[16, 16]">
        <a-col :span="12">
          <a-form-item
            label="产品"
            :rules="[{ required: true, message: '该项必填！' }]"
          >
            <a-select
              showSearch
              optionFilterProp="lable"
              @select="select"
              v-model:value="province"
              placeholder="请选择产品"
              :allowClear="true"
            >
              <a-select-option
                v-for="item in productList"
                :key="item.productId"
                :lable="item.productName"
                :value="item.productId"
              >
                {{ item.productName }}
              </a-select-option>
            </a-select>
          </a-form-item>
        </a-col>
        <a-col :span="12">
          <a-form-item
            label="检测项"
            :rules="[{ required: true, message: '该项必填！' }]"
          >
            <a-tree-select
              showSearch
              treeNodeFilterProp="checkItemName"
              v-model:value="form.checkItemId"
              style="width: 180px"
              placeholder="请选择检测项"
              :dropdown-style="{ maxHeight: '400px', overflow: 'auto' }"
              notFoundContent="未选择产品或产品下没有检测项"
              allow-clear
              :tree-data="productItemList"
              :replaceFields="{
                children: 'children',
                label: 'checkItemName',
                key: 'checkItemId',
                value: 'checkItemId',
              }"
            ></a-tree-select>
          </a-form-item>
        </a-col>
      </a-row>

      <a-row :gutter="[16, 16]">
        <a-col :span="6">
          <a-form-item label="模板地址">
            <a-input v-model:value="form.fileUrl" disabled />
          </a-form-item>
        </a-col>
        <a-col :span="6">
          <a-upload
            v-model:file="file"
            :show-upload-list="false"
            :customRequest="customRequest"
            :before-upload="beforeUpload"
          >
            <a-button v-if="form.fileUrl">
              <UploadOutlined></UploadOutlined>
              点击修改文件
            </a-button>
            <a-button v-else>
              <UploadOutlined></UploadOutlined>
              点击上传文件
            </a-button>
          </a-upload>
        </a-col>

        <a-col :span="12">
          <a-form-item label="模板名称" name="name">
            <a-input placeholder="请输入模板名称" v-model:value="form.name" />
          </a-form-item>
        </a-col>
      </a-row>

      <a-row :gutter="[16, 16]">
        <a-col :span="24">
          <a-form-item label="备注">
            <a-textarea
              rows="4"
              placeholder="请输入备注"
              v-model:value="form.remark"
              show-count
              :maxlength="100"
            />
          </a-form-item>
        </a-col>
      </a-row>
    </a-form>
  </a-modal>
</template>

<script>
const columns = [
  {
    title: "模板编号",
    dataIndex: "code",
  },
  {
    title: "模板名称",
    dataIndex: "name",
  },
  {
    title: "检测项",
    dataIndex: "checkitemname",
  },

  {
    title: "是否可用",
    dataIndex: "isAvailable",
    slots: { customRender: "isAvailable" },
  },
  {
    title: "备注",
    dataIndex: "remark",
  },
  {
    title: "操作",
    dataIndex: "operation",
    slots: { customRender: "operation" },
  },
];
const rules = {
  name: [{ required: true, message: "该为必填项", trigger: "blur" }],
};
import {
  testOriginalRecordTemplateList,
  addtestOriginalRecordTemplate,
  gettestOriginalRecordTemplate,
  deltestOriginalRecordTemplate,
  editestOriginalRecordTemplate,
} from "@/server/http/api/testOriginalRecordTemplate";
import { UploadOutlined } from "@ant-design/icons-vue";
import { message } from "ant-design-vue";
import { uploadFile, delFile } from "@/server/http/api/File";
import { ProductListAll, itemList, getitem } from "@/server/http/api/Product";
export default {
  name: "QueryList",
  components: { UploadOutlined },
  data() {
    return {
      // 弹出层标题
      title: "",
      // 是否显示弹出层
      open: false,
      advanced: false,
      columns: columns,
      rules: rules,
      dataSource: [],
      selectedRows: [],
      selectedRowKeys: [],
      // 表单参数
      form: {},
      file: null,
      Pagination: {},
      total: 0,
      queryParams: {
        current: 1,
        size: 10,
        checkItemName: undefined,
      },
      // 选中数组
      ids: [],
      // 非单个禁用
      single: true,
      // 非多个禁用
      multiple: true,
      // 产品列表
      productList: [],
      // 产品检测项
      productItemList: [],
      //暂存产品ID
      province: null,
      //用来存储修改的临时文件路径
      updateUrl: null,
    };
  },
  authorize: {
    deleteRecord: "delete",
  },
  created() {
    this.getList();
  },
  mounted() {
    this.getProductList();
  },
  watch: {
    province(e) {
      if (e == null || e == "") {
        this.productItemList = [];
        return;
      }
      itemList({
        productId: e,
        status: "0",
      }).then((res) => {
        var data = res.data;
        this.productItemList = data.data;
      });
    },
  },
  methods: {
    select() {
      this.form.checkItemId = null;
    },
    onSel(url) {
      window.location.href = url;
    },
    delFileMethod(e) {
      delFile({ fileUrl: e }).then((res) => {});
    },
    //文件上传
    customRequest(info) {
      const formData = new FormData();
      formData.append("file", info.file);

      if (this.form.fileUrl != null && this.updateUrl != this.form.fileUrl) {
        this.delFileMethod(this.form.fileUrl);
      }
      uploadFile(formData).then((res) => {
        this.form.fileUrl = res.data.data.fileUrl;
        let fileName = res.data.data.fileName;
        this.form.reportName = fileName.substring(0, fileName.lastIndexOf("."));
      });
    },
    //文件上传
    beforeUpload(file) {
      let fileFormat = file.name.substring(
        file.name.lastIndexOf(".") + 1,
        file.name.length
      );
      const isJpgOrPng =
        fileFormat === "doc" ||
        fileFormat === "pdf" ||
        fileFormat === "docx" ||
        fileFormat === "xls" ||
        fileFormat === "xlsx";
      if (!isJpgOrPng) {
        message.error("只能上传word、pdf、excel!");
      }
      return isJpgOrPng;
    },
    onShowSizeChange(current, pageSize) {
      this.queryParams.current = current;
      this.queryParams.size = pageSize;
      this.getList();
    },
    onPageChange(pageNumber) {
      this.queryParams.current = pageNumber;
      this.getList();
    },
    //获取设备分类列表
    getList() {
      testOriginalRecordTemplateList(this.queryParams).then((res) => {
        var data = res.data;
        this.dataSource = data.data.records;
        this.total = data.data.total;
      });
    },

    //获取产品列表
    getProductList() {
      ProductListAll().then((res) => {
        var data = res.data;
        this.productList = data.data;
      });
    },
    //查询数据
    handleSearch() {
      this.getList();
    },
    Reset() {
      this.queryParams = {
        current: 1,
        size: 10,
        name: undefined,
      };
      this.getList();
    },
    handleOk(e) {
      if (!this.form.name || !this.form.checkItemId) {
        message.warning("缺少必填参数!");
        return;
      }
      this.submitForm();
    },
    handleCancel(e) {
      if (this.form.fileUrl != null && this.updateUrl != this.form.fileUrl) {
        this.delFileMethod(this.form.fileUrl);
      }
      this.form = {};
      this.open = false;
    },
    deleteRecord(key) {
      this.dataSource = this.dataSource.filter((item) => item.key !== key);
      this.selectedRows = this.selectedRows.filter((item) => item.key !== key);
    },
    toggleAdvanced() {
      this.advanced = !this.advanced;
    },
    remove() {
      this.dataSource = this.dataSource.filter(
        (item) =>
          this.selectedRows.findIndex((row) => row.key === item.key) === -1
      );
      this.selectedRows = [];
    },
    onSelectChange(selection) {
      this.ids = selection.map((item) => item.id);
      this.single = selection.length !== 1;
      this.multiple = !selection.length;
      this.selectedRowKeys = selection;
    },
    /** 新增按钮操作 */
    handleAdd() {
      this.open = true;
      this.title = "添加原始记录模板";
    },
    /** 修改按钮操作 */
    handleUpdate(row) {
      this.loading = true;
      gettestOriginalRecordTemplate(this.selectedRowKeys[0]).then(
        (response) => {
          this.loading = false;
          this.form = response.data.data;
          this.open = true;
          this.title = "修改原始记录模板";
          this.updateUrl = response.data.data.fileUrl;
          getitem(this.form.checkItemId).then((response) => {
            this.province = response.data.data.testProductItem.productId;
          });
        }
      );
    },
    /** 提交按钮 */
    submitForm() {
      this.buttonLoading = true;
      if (this.form.id != null) {
        if (this.form.fileUrl != this.updateUrl) {
          this.delFileMethod(this.updateUrl);
        }
        editestOriginalRecordTemplate(this.form)
          .then((response) => {
            this.open = false;
            this.form = {};
            this.getList();
          })
          .finally(() => {
            this.buttonLoading = false;
          });
      } else {
        addtestOriginalRecordTemplate(this.form)
          .then((response) => {
            this.open = false;
            this.form = {};
            this.getList();
          })
          .finally(() => {
            this.buttonLoading = false;
          });
      }
    },
    handleDel() {
      deltestOriginalRecordTemplate(this.selectedRowKeys)
        .then((response) => {
          this.selectedRowKeys = [];
          this.getList();
        })
        .finally(() => {
          this.buttonLoading = false;
        });
    },
  },
};
</script>

<style lang="less" scoped>
.search {
  margin-bottom: 54px;
}
.fold {
  width: calc(100% - 216px);
  display: inline-block;
}
.operator {
  margin-bottom: 18px;
}
@media screen and (max-width: 900px) {
  .fold {
    width: 100%;
  }
}
</style>
